Package main

import "fmt"

func main() {
    // Ask user for temperature in Fahrenheit
    fmt.Print("Enter temperature in Fahrenheit: ")
    var fahrenheit float64
    _, err := fmt.Scanf("%f", &fahrenheit)
    if err != nil {
        fmt.Println(err)
        return
    }

    // Convert Fahrenheit to Celsius using the formula C = (F - 32) * 5 / 9
    celsius := (fahrenheit - 32) * 5 / 9

    // Output the converted temperature in Celsius
    fmt.Printf("%.1f degrees Fahrenheit is %.1f degrees Celsius.", fahrenheit, celsius)
} 

/*
Sample Output:

Enter temperature in Fahrenheit: 72.5
72.5 degrees Fahrenheit is 22.5 degrees Celsius.
*/
